# --- grid helper (hidden) — the 4-bit adder doubling each number ---
# Laid out wide (the canvas has more room sideways): each COLUMN shows n + n
# computed by the student's own add4, in 5-bit binary (the sum can reach 30, so
# there's a 16s place). Read down a column for its bits. Until add4 works the
# bit cells show '?'; the number row and place-value labels always render.
def __grid():
    add = globals().get("add4")
    nums = list(range(16))

    def sum_of(n):
        if add is None:
            return None
        try:
            v = add(n, n)
            return v if isinstance(v, int) else None
        except Exception:
            return None

    sums = [sum_of(n) for n in nums]
    rows = [["n"] + [str(n) for n in nums]]
    for p_idx, place in enumerate([16, 8, 4, 2, 1]):
        shift = 4 - p_idx
        row = [str(place)]
        for n in nums:
            s = sums[n]
            if s is None:
                row.append("?")
            elif (s >> shift) & 1:
                row.append("green")
            else:
                row.append("")
        rows.append(row)
    return {
        "grid": rows,
        "caption": "Each column shows n + n (double it!) from your add4, in binary - read down: 16s, 8s, 4s, 2s, 1s. The lit pattern climbs as the sum grows, and the 1s row is always empty because doubling is always even. A ? means add4 isn't finished yet.",
    }
